import{_ as n,M as i,p as r,q as o,R as e,t as s,N as l,a1 as a}from"./framework-96b046e1.js";const d="/learning-ai/assets/turing_test-44026f5f.png",c="/learning-ai/assets/gasparov-e342815a.jpg",p="/learning-ai/assets/jeopardy-6e443200.jpg",h="/learning-ai/assets/alphago-d8e135fe.png",g="/learning-ai/assets/market-4afd2dcb.png",u="/learning-ai/assets/top50-ef23eb41.png",m={},f=a('<h1 id="let-s-start" tabindex="-1"><a class="header-anchor" href="#let-s-start" aria-hidden="true">#</a> Let&#39;s start</h1><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>LLMs and MMLLMs are constantly evolving, and new applications for developer training are emerging all the time.</p></div><h2 id="prerequisites" tabindex="-1"><a class="header-anchor" href="#prerequisites" aria-hidden="true">#</a> Prerequisites</h2><h4 id="shell-command-line-skills" tabindex="-1"><a class="header-anchor" href="#shell-command-line-skills" aria-hidden="true">#</a> <strong>Shell Command Line Skills:</strong></h4><p>The AI should include support for providing guidance on using shell commands, navigating file systems, and executing command-line operations across different operating systems.</p><h4 id="understanding-of-http-and-api" tabindex="-1"><a class="header-anchor" href="#understanding-of-http-and-api" aria-hidden="true">#</a> <strong>Understanding of HTTP and API:</strong></h4><p>Proficiency in HTTP protocol, RESTful API concepts, and web service integration is crucial for the AI to provide support on API design, consumption, and troubleshooting common API-related issues.</p><h4 id="basic-cloud-knowledge" tabindex="-1"><a class="header-anchor" href="#basic-cloud-knowledge" aria-hidden="true">#</a> <strong>Basic Cloud Knowledge:</strong></h4><p>Understanding of cloud computing principles, including basic concepts of cloud infrastructure, services, and deployment models, will enable the AI to offer guidance on cloud-based development, deployment, and best practices.</p><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>Additionnaly, <strong>Request Worldline librechat access:</strong> send a mail at <a href="mailto:GenAITaskforce@worldline.com">Generative AI Taskforce email</a></p></div><h2 id="definitions" tabindex="-1"><a class="header-anchor" href="#definitions" aria-hidden="true">#</a> Definitions</h2><h3 id="llm" tabindex="-1"><a class="header-anchor" href="#llm" aria-hidden="true">#</a> LLM</h3><p>Large Language Model is a powerful type of AI model trained on massive datasets of text and code. LLMs can understand, generate, and manipulate language. Ex : ChatGPT, Bard, Codex</p><p><em>What are Large Language Models (LLMs)? by Google for developpers</em></p>',14),b=e("iframe",{width:"560",height:"315",src:"https://www.youtube.com/embed/iR2O2GPbB0E",title:"What are Large Language Models (LLMs)? by Google for developpers",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""},null,-1),v=a('<h3 id="mmllm" tabindex="-1"><a class="header-anchor" href="#mmllm" aria-hidden="true">#</a> MMLLM</h3><p>Multi-Modal Large Language Model is an advanced LLM that can process and generate both text and other data formats like images, audio, or video. Ex: DALL-E 2, Stable Diffusion (for image generation)</p><h3 id="ml" tabindex="-1"><a class="header-anchor" href="#ml" aria-hidden="true">#</a> ML</h3><p>Machine Learning is a subset of AI that focuses on training algorithms to learn from data and make predictions or decisions without explicit programming. ML powers many AI applications, including image recognition, natural language processing, and predictive analytics.</p><h3 id="dl" tabindex="-1"><a class="header-anchor" href="#dl" aria-hidden="true">#</a> DL</h3><p>Deep Learning is a type of ML that uses artificial neural networks with multiple layers to learn complex patterns from data.DL has revolutionized fields like computer vision, speech recognition, and machine translation.</p><h3 id="neural-network" tabindex="-1"><a class="header-anchor" href="#neural-network" aria-hidden="true">#</a> Neural Network</h3><p>A computational model inspired by the structure of the human brain, consisting of interconnected nodes (neurons) organized in layers.Neural networks are the core building blocks of deep learning models.</p><h4 id="nlp" tabindex="-1"><a class="header-anchor" href="#nlp" aria-hidden="true">#</a> NLP</h4><p>Natural Language Processing is a branch of Artificial Intelligence (AI) that focuses on enabling computers to understand, interpret, and generate human language. It implies :</p><ul><li>Text Analysis</li><li>Language Understanding</li><li>Text Generation</li><li>Translation</li><li>Speech Recognition: Powers voice assistants and speech-to-text technologies</li></ul><h4 id="prompt" tabindex="-1"><a class="header-anchor" href="#prompt" aria-hidden="true">#</a> <strong>Prompt:</strong></h4><p>A specific set of instructions or questions given to an LLM to guide its response. Well-crafted prompts are crucial for getting accurate and relevant output from LLMs. Ex : &quot;Write a Python function to check if a string is a palindrome.&quot;</p><h4 id="token" tabindex="-1"><a class="header-anchor" href="#token" aria-hidden="true">#</a> <strong>Token:</strong></h4><p>The smallest unit of meaning processed by an LLM. Tokens can be words, parts of words, punctuation marks, or special characters. LLMs process text by analyzing sequences of tokens, making it important to understand how they are broken down. Ex : The sentence &quot;I love programming&quot; would be split into the following tokens: &quot;I&quot;, &quot;love&quot;, &quot;programming&quot;.</p><h4 id="temperature" tabindex="-1"><a class="header-anchor" href="#temperature" aria-hidden="true">#</a> <strong>Temperature:</strong></h4><p>A parameter in some LLMs that controls the randomness or creativity of the generated text. Adjust temperature based on the desired level of creativity or accuracy in the LLM&#39;s output.</p><ul><li>A higher temperature generate more randomness and unpredictability in the output.</li><li>A lower temperature generate more predictable and coherent output.</li></ul><h4 id="rag-retrieval-augmented-generation" tabindex="-1"><a class="header-anchor" href="#rag-retrieval-augmented-generation" aria-hidden="true">#</a> <strong>RAG: Retrieval Augmented Generation</strong></h4><p>RAG (Retrieval Augmented Generation) is a powerful technique in the field of Natural Language Processing (NLP) that combines the best of both worlds: information retrieval and language generation.</p><ul><li>The system first retrieves relevant information from a vast knowledge base (often a database or a set of documents) based on the user&#39;s query or prompt.</li><li>This retrieved information is then used to augment the language model&#39;s input, providing it with more context and specific facts.</li><li>Finally, the language model uses this augmented input to generate a more comprehensive and informative response, leveraging both its knowledge base and its language generation capabilities.</li></ul><h2 id="a-bit-of-history" tabindex="-1"><a class="header-anchor" href="#a-bit-of-history" aria-hidden="true">#</a> A bit of History</h2><p>AI&#39;s history has been marked by periods of progress and setbacks. Computing power, data availability, and algorithmic advancements have played crucial roles in AI&#39;s evolution. AI is no longer limited to expert systems but encompasses a wide range of techniques and applications.</p><ul><li><strong>1950:</strong> Alan Turing proposes the &quot;Turing Test&quot; to assess machine intelligence.</li></ul><p>During the turing test, the human questioner asks a series of questions to both respondantes. After the specified time, the questionner tries to decide which terminal is operated bu the human respondant and which terminal is operated by the computer.</p><p><img src="'+d+'" alt="turing"></p><ul><li><p><strong>1956:</strong> Dartmouth Conference establishes the field of &quot;Artificial Intelligence&quot;.</p></li><li><p><strong>1959:</strong> Arthur Samuel develops a checkers-playing program that learns and improves over time.</p></li><li><p><strong>1960s:</strong> Research focused on logic-based reasoning and early expert systems.</p></li><li><p><strong>1972:</strong> The first expert system, DENDRAL, is developed for identifying organic molecules.</p></li><li><p><strong>1980s-1990s:</strong> Development of new techniques like machine learning and neural networks.</p></li><li><p><strong>1997:</strong> Deep Blue, a chess-playing computer, defeats Garry Kasparov, the world chess champion. <img src="'+c+'" alt="gasparov"></p></li><li><p><strong>1990s-2000s:</strong> Advances in computing power, data availability, and algorithms as fuel for AI progress.</p></li><li><p><strong>2010s:</strong> Deep learning revolutionizes AI with breakthroughs in image recognition, speech recognition, and natural language processing.</p></li><li><p><strong>2011:</strong> Watson, an IBM supercomputer, wins Jeopardy! against human champions. <img src="'+p+'" alt="jeopardy"></p></li><li><p><strong>2016:</strong> AlphaGo, a program developed by Google DeepMind, defeats Go champion Lee Sedol. <img src="'+h+'" alt="alphago"></p></li><li><p><strong>2022:</strong> First release of ChatGPT : AI continues to evolve rapidly, with advancements in areas like autonomous vehicles, robotics, and personalized medicine.</p></li></ul><h2 id="the-market" tabindex="-1"><a class="header-anchor" href="#the-market" aria-hidden="true">#</a> The market</h2><p><img src="'+g+'" alt="market"></p><p><img src="'+u+'" alt="top50"></p><h2 id="📖-further-readings" tabindex="-1"><a class="header-anchor" href="#📖-further-readings" aria-hidden="true">#</a> 📖 Further readings</h2>',31),L=e("li",null,[e("a",{href:"mailto:GenAITaskforce@worldline.com"},"Generative AI Taskforce email")],-1),y={href:"https://a16z.com/100-gen-ai-apps/",target:"_blank",rel:"noopener noreferrer"};function w(k,x){const t=i("ExternalLinkIcon");return r(),o("div",null,[f,b,v,e("ul",null,[L,e("li",null,[e("a",y,[s("Top 100 GenAI"),l(t)])])])])}const _=n(m,[["render",w],["__file","index.html.vue"]]);export{_ as default};
